class Solution {
public:
    int characterReplacement(string s, int k) {
        vector<int> cnt(26, 0);
        int left = 0, maxFreq = 0, ans = 0;
        int n = s.size();
        for (int right = 0; right < n; right++) {
            cnt[s[right] - 'A']++;
            maxFreq = max(maxFreq, cnt[s[right] - 'A']);
            // (window length) - (most frequent char count) = number of chars
            // that must be replaced to make the whole window uniform.
            while ((right - left + 1) - maxFreq > k) {
                cnt[s[left] - 'A']--;
                left++;
            }
            ans = max(ans, right - left + 1);
        }
        return ans;
    }
};

class Solution
{
public:
    int maximalAreaOfSubMatrixOfAll1(vector<vector<int>> &matrix){
        if (matrix.empty() || matrix[0].empty()) return 0;
        int rows = matrix.size();
        int cols = matrix[0].size();
        vector<int> heights(cols, 0);
        int maxArea = 0;
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (matrix[i][j] == 1) heights[j] += 1;
                else heights[j] = 0;
            }
            maxArea = max(maxArea, largestRectangleArea(heights));
        }
        return maxArea;
    }

private:
    int largestRectangleArea(vector<int>& h) {
        int n = h.size();
        stack<int> st;
        int best = 0;
        for (int i = 0; i <= n; i++) {
            int cur = (i == n) ? 0 : h[i];
            while (!st.empty() && h[st.top()] >= cur) {
                int height = h[st.top()];
                st.pop();
                int left = st.empty() ? -1 : st.top();
                int width = i - left - 1;
                best = max(best, height * width);
            }
            st.push(i);
        }
        return best;
    }
};

class Solution {
public:
    vector<int> leaders(vector<int>& nums) {
        int n = nums.size();
        vector<int> res;
        int maxRight = INT_MIN;
        for (int i = n - 1; i >= 0; --i) {
            if (nums[i] > maxRight) {
                res.push_back(nums[i]);
                maxRight = nums[i];
            }
        }
        reverse(res.begin(), res.end());
        return res;
    }
};

class Solution {
public:
    int ninjaTraining(vector<vector<int>>& matrix) {
        int n = matrix.size();
        if (n == 0) return 0;
        // dp[t] = max merit through current day when current day's activity is t
        vector<int> dp(3);
        for (int t = 0; t < 3; t++) dp[t] = matrix[0][t];
        for (int day = 1; day < n; day++) {
            vector<int> cur(3);
            for (int t = 0; t < 3; t++) {
                int bestPrev = 0;
                for (int p = 0; p < 3; p++)
                    if (p != t) bestPrev = max(bestPrev, dp[p]);
                cur[t] = matrix[day][t] + bestPrev;
            }
            dp = cur;
        }
        return max({dp[0], dp[1], dp[2]});
    }
};

class Solution {
public:
    int myAtoi(string input) {
        int n = input.size();
        int i = 0;
        // 1. Skip leading whitespace
        while (i < n && input[i] == ' ') i++;
        // 2. Determine sign
        int sign = 1;
        if (i < n && (input[i] == '+' || input[i] == '-')) {
            if (input[i] == '-') sign = -1;
            i++;
        }
        // 3. Read digits with clamping to 32-bit signed range
        long long result = 0;
        const long long INT_MAX_LL = 2147483647LL;
        const long long INT_MIN_LL = -2147483648LL;
        while (i < n && input[i] >= '0' && input[i] <= '9') {
            int digit = input[i] - '0';
            result = result * 10 + digit;
            // clamp early to avoid long long overflow on very long inputs
            if (sign == 1 && result > INT_MAX_LL) return (int)INT_MAX_LL;
            if (sign == -1 && -result < INT_MIN_LL) return (int)INT_MIN_LL;
            i++;
        }
        result *= sign;
        if (result > INT_MAX_LL) return (int)INT_MAX_LL;
        if (result < INT_MIN_LL) return (int)INT_MIN_LL;
        return (int)result;
    }
};

class Solution {
public:
    int MOD = 1000000007;
    map<tuple<int,int,int>, long long> memo;
    long long solve(int i, int j, int isTrue, string &s) {
        if (i > j) return 0;
        if (i == j) {
            if (isTrue) return s[i] == 'T';
            else return s[i] == 'F';
        }
        auto key = make_tuple(i, j, isTrue);
        auto it = memo.find(key);
        if (it != memo.end()) return it->second;
        long long ways = 0;
        for (int k = i + 1; k < j; k += 2) {
            long long lT = solve(i, k - 1, 1, s);
            long long lF = solve(i, k - 1, 0, s);
            long long rT = solve(k + 1, j, 1, s);
            long long rF = solve(k + 1, j, 0, s);
            char op = s[k];
            if (op == '&') {
                if (isTrue) ways += lT * rT;
                else ways += lT * rF + lF * rT + lF * rF;
            } else if (op == '|') {
                if (isTrue) ways += lT * rT + lT * rF + lF * rT;
                else ways += lF * rF;
            } else { // ^
                if (isTrue) ways += lT * rF + lF * rT;
                else ways += lT * rT + lF * rF;
            }
            ways %= MOD;
        }
        return memo[key] = ways % MOD;
    }
    int countTrue(string s) {
        memo.clear();
        int n = s.size();
        return (int)(solve(0, n - 1, 1, s) % MOD);
    }
};

class Solution {
public:
    vector<int> rearrangeArray(vector<int>& nums) {
        int n = nums.size();
        vector<int> ans(n, 0);
        int pos = 0, neg = 1;
        for (int i = 0; i < n; i++) {
            if (nums[i] > 0) {
                ans[pos] = nums[i];
                pos += 2;
            } else {
                ans[neg] = nums[i];
                neg += 2;
            }
        }
        return ans;
    }
};

class Solution {
public:
    vector<int> replaceWithRank(vector<int>& arr) {
        vector<int> sorted_unique(arr.begin(), arr.end());
        sort(sorted_unique.begin(), sorted_unique.end());
        sorted_unique.erase(unique(sorted_unique.begin(), sorted_unique.end()), sorted_unique.end());
        vector<int> res;
        res.reserve(arr.size());
        for (int x : arr) {
            int rank = (int)(lower_bound(sorted_unique.begin(), sorted_unique.end(), x) - sorted_unique.begin()) + 1;
            res.push_back(rank);
        }
        return res;
    }
};

class Solution {
public:
    vector<int> findPeakGrid(vector<vector<int>>& mat) {
        int n = mat.size();
        int m = mat[0].size();
        int low = 0, high = m - 1;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            // find row index of the maximum element in column `mid`
            int maxRow = 0;
            for (int i = 1; i < n; i++) {
                if (mat[i][mid] > mat[maxRow][mid]) maxRow = i;
            }
            int left  = (mid - 1 >= 0) ? mat[maxRow][mid - 1] : -1;
            int right = (mid + 1 < m)  ? mat[maxRow][mid + 1] : -1;
            int cur = mat[maxRow][mid];
            if (cur > left && cur > right) {
                return {maxRow, mid};
            } else if (cur < left) {
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return {-1, -1};
    }
};

class Solution{
    public:
    int findPlatform(vector<int>& Arrival, vector<int>& Departure){
        int n = Arrival.size();
        if(n == 0) return 0;
        vector<int> arr = Arrival, dep = Departure;
        sort(arr.begin(), arr.end());
        sort(dep.begin(), dep.end());
        int i = 0, j = 0, plat = 0, ans = 0;
        while (i < n) {
            if (arr[i] <= dep[j]) {
                // A train arrives (at the same time another departs, the
                // platform cannot be reused) -> need an extra platform.
                i++;
                plat++;
                ans = max(ans, plat);
            } else {
                // The earliest-departing train has left -> free a platform.
                j++;
                plat--;
            }
        }
        return ans;
    }
};

class Solution {
public:
    struct Node {
        Node* links[2];
        Node() { links[0] = links[1] = nullptr; }
    };
    struct Trie {
        Node* root;
        Trie() { root = new Node(); }
        void insert(int num) {
            Node* cur = root;
            for (int i = 31; i >= 0; i--) {
                int bit = (num >> i) & 1;
                if (cur->links[bit] == nullptr) cur->links[bit] = new Node();
                cur = cur->links[bit];
            }
        }
        int getMax(int num) {
            Node* cur = root;
            int maxNum = 0;
            for (int i = 31; i >= 0; i--) {
                int bit = (num >> i) & 1;
                if (cur->links[1 - bit] != nullptr) {
                    maxNum |= (1 << i);
                    cur = cur->links[1 - bit];
                } else {
                    cur = cur->links[bit];
                }
            }
            return maxNum;
        }
    };

    vector<int> maximizeXor(vector<int>& nums, vector<vector<int> >& queries) {
        sort(nums.begin(), nums.end());
        int q = queries.size();
        vector<array<int,3>> offline; // {m, x, idx}
        for (int i = 0; i < q; i++) {
            offline.push_back({queries[i][1], queries[i][0], i});
        }
        sort(offline.begin(), offline.end());
        vector<int> ans(q, -1);
        Trie trie;
        int ptr = 0;
        int n = nums.size();
        for (auto& qe : offline) {
            int m = qe[0], x = qe[1], idx = qe[2];
            while (ptr < n && nums[ptr] <= m) {
                trie.insert(nums[ptr]);
                ptr++;
            }
            if (ptr == 0) {
                ans[idx] = -1;
            } else {
                ans[idx] = trie.getMax(x);
            }
        }
        return ans;
    }
};

class Solution {
public:
    void solve(int start, vector<int>& candidates, int target, vector<int>& temp, vector<vector<int>>& ans) {
        if (target == 0) {
            ans.push_back(temp);
            return;
        }
        if (target < 0) return;
        for (int i = start; i < (int)candidates.size(); i++) {
            if (candidates[i] <= target) {
                temp.push_back(candidates[i]);
                solve(i, candidates, target - candidates[i], temp, ans);
                temp.pop_back();
            }
        }
    }
    vector<vector<int>> combinationSum(vector<int>& candidates, int target) {
        vector<vector<int>> ans;
        vector<int> temp;
        solve(0, candidates, target, temp, ans);
        return ans;
    }
};

class Solution {
public:
    vector<int> divisors(int n) {
        vector<int> res;
        for (int i = 1; (long long)i * i <= (long long)n; i++) {
            if (n % i == 0) {
                res.push_back(i);
                if (i != n / i) res.push_back(n / i);
            }
        }
        sort(res.begin(), res.end());
        return res;
    }
};

class Solution{
public:
    bool isCyclic(int N, vector<int> adj[]) {
        vector<int> indeg(N, 0);
        for (int i = 0; i < N; i++)
            for (int v : adj[i])
                indeg[v]++;
        queue<int> q;
        for (int i = 0; i < N; i++)
            if (indeg[i] == 0) q.push(i);
        int cnt = 0;
        while (!q.empty()) {
            int u = q.front(); q.pop();
            cnt++;
            for (int v : adj[u])
                if (--indeg[v] == 0) q.push(v);
        }
        return cnt != N;
    }
};

class Solution
{
    public:
    vector <int> stockSpan(vector<int> arr, int n) {
        vector<int> span(n);
        stack<int> st; // indices of previous strictly greater elements
        for (int i = 0; i < n; i++) {
            while (!st.empty() && arr[st.top()] <= arr[i]) {
                st.pop();
            }
            if (st.empty()) span[i] = i + 1;
            else span[i] = i - st.top();
            st.push(i);
        }
        return span;
    }
};

