class Solution {
public:
    string minWindow(string s1, string s2) {
        int n = s1.size();
        string ans = "";
        int r = 0, r2 = 0, len = INT_MAX;
        while (r < n) {
            if (s1[r] == s2[r2]) r2++;
            if (r2 == (int)s2.size()) {
                int l = r;
                r2--;
                while (l >= 0 && r2 >= 0) {
                    if (s1[l] == s2[r2]) r2--;
                    l--;
                }
                l++;
                if (r - l + 1 < len) {
                    len = r - l + 1;
                    ans = s1.substr(l, r - l + 1);
                }
                r2 = 0;
                r = l + 1;
            }
            r++;
        }
        return ans;
    }
};

class Solution {
public:
    int shipWithinDays(vector<int>& weights, int days) {
        long long lo = 0, hi = 0;
        for (int w : weights) {
            lo = max(lo, (long long)w); // capacity must hold the heaviest package
            hi += w;                    // upper bound: ship everything in one day
        }
        auto daysNeeded = [&](long long cap) -> long long {
            long long d = 1, cur = 0;
            for (int w : weights) {
                if (cur + w > cap) { d++; cur = w; }
                else cur += w;
            }
            return d;
        };
        long long ans = hi;
        while (lo <= hi) {
            long long mid = lo + (hi - lo) / 2;
            if (daysNeeded(mid) <= (long long)days) { ans = mid; hi = mid - 1; }
            else lo = mid + 1;
        }
        return (int)ans;
    }
};

