class Solution {
  public:
    vector<int> longestIncreasingSubsequence(vector<int>& arr) {
        int n = arr.size();
        vector<int> dp(n, 1);
        vector<int> prevmap(n, -1);
        for (int i = 0; i < n; i++) {
            for (int prev = 0; prev < i; prev++) {
                if (arr[prev] < arr[i] && dp[i] < dp[prev] + 1) {
                    dp[i] = dp[prev] + 1;
                    prevmap[i] = prev;
                }
            }
        }
        int idx = (int)(max_element(dp.begin(), dp.end()) - dp.begin());
        vector<int> lis;
        int i = idx;
        while (i >= 0) {
            lis.push_back(arr[i]);
            i = prevmap[i];
        }
        reverse(lis.begin(), lis.end());
        return lis;
    }
};

class Solution{
public:
    int countPaths(int n, vector<vector<int>> &roads) {
        vector<vector<pair<int,long long>>> adj(n);
        for (auto &road : roads) {
            adj[road[0]].push_back({road[1], (long long)road[2]});
            adj[road[1]].push_back({road[0], (long long)road[2]});
        }

        const long long MOD = 1e9 + 7;
        priority_queue<pair<long long,int>, vector<pair<long long,int>>, greater<pair<long long,int>>> pq;
        vector<long long> dis(n, LLONG_MAX);
        vector<long long> ways(n, 0);

        dis[0] = 0;
        ways[0] = 1;
        pq.push({0, 0});

        while (!pq.empty()) {
            auto [uwt, u] = pq.top();
            pq.pop();
            if (uwt > dis[u]) continue;

            for (auto [v, vwt] : adj[u]) {
                long long nd = uwt + vwt;
                if (nd < dis[v]) {
                    dis[v] = nd;
                    ways[v] = ways[u];
                    pq.push({dis[v], v});
                } else if (nd == dis[v]) {
                    ways[v] = (ways[v] + ways[u]) % MOD;
                }
            }
        }

        return (int)(ways[n - 1] % MOD);
    }
};

class Solution{
public:
    bool isSafe(int node, int col, vector<vector<int>>& adj, vector<int>& color){
        for(int neigh : adj[node]){
            if(color[neigh] == col) return false;
        }
        return true;
    }
    bool solve(int node, int m, int n, vector<vector<int>>& adj, vector<int>& color){
        if(node == n) return true;
        for(int c = 1; c <= m; c++){
            if(isSafe(node, c, adj, color)){
                color[node] = c;
                if(solve(node+1, m, n, adj, color)) return true;
                color[node] = 0;
            }
        }
        return false;
    }
    bool graphColoring(vector<vector<int> >& edges, int m, int n) {
        vector<vector<int>> adj(n);
        for(auto& e : edges){
            int u = e[0], v = e[1];
            if(u >= 0 && u < n && v >= 0 && v < n && u != v){
                adj[u].push_back(v);
                adj[v].push_back(u);
            }
        }
        vector<int> color(n, 0);
        return solve(0, m, n, adj, color);
    }
};

class Solution{
public:
    int upperBound(vector<int> &nums, int x){
        int n = nums.size();
        int low = 0, high = n - 1;
        int ans = n;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (nums[mid] > x) {
                ans = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return ans;
    }
};

class Solution {
public:
    vector<int> bubbleSort(vector<int>& nums) {
        sortRec(nums, (int)nums.size());
        return nums;
    }
private:
    void sortRec(vector<int>& nums, int n) {
        if (n <= 1) return;
        for (int i = 0; i < n - 1; i++) {
            if (nums[i] > nums[i + 1]) {
                swap(nums[i], nums[i + 1]);
            }
        }
        sortRec(nums, n - 1);
    }
};

class Solution{
	public:
		int matrixMultiplication(vector<int>& nums){
            int n = nums.size();
            // dp[i][j] = min scalar multiplications to multiply matrices i..j
            // Matrix A_k has dimensions nums[k-1] x nums[k], for k = 1..n-1.
            vector<vector<long long>> dp(n, vector<long long>(n, 0));
            for (int len = 2; len <= n - 1; len++) {
                for (int i = 1; i + len - 1 <= n - 1; i++) {
                    int j = i + len - 1;
                    long long mini = LLONG_MAX;
                    for (int k = i; k < j; k++) {
                        long long cost = (long long)nums[i-1] * nums[k] * nums[j]
                                         + dp[i][k] + dp[k+1][j];
                        mini = min(mini, cost);
                    }
                    dp[i][j] = mini;
                }
            }
            return (int)dp[1][n-1];
    	}
};

