class Solution {
public:
    int fib(int n) {
        if (n <= 1) return n;
        int a = 0, b = 1;
        for (int i = 2; i <= n; i++) {
            int c = a + b;
            a = b;
            b = c;
        }
        return b;
    }
};

class Solution{
public:
    bool dfsCheck(int node, vector<int> adj[], vector<int>& vis, vector<int>& pathVis) {
        vis[node] = 1;
        pathVis[node] = 1;
        for (int it : adj[node]) {
            if (!vis[it]) {
                if (dfsCheck(it, adj, vis, pathVis)) return true;
            } else if (pathVis[it]) {
                return true;
            }
        }
        pathVis[node] = 0;
        return false;
    }
    bool isCyclic(int N, vector<int> adj[]) {
        vector<int> vis(N, 0), pathVis(N, 0);
        for (int i = 0; i < N; i++) {
            if (!vis[i]) {
                if (dfsCheck(i, adj, vis, pathVis)) return true;
            }
        }
        return false;
    }
};

