class Solution{
public:
 vector<int> eventualSafeNodes(int V, vector<int> adj[]){
    vector<vector<int>> revadj(V);
    vector<int> outdeg(V, 0);
    for (int i = 0; i < V; i++) {
        outdeg[i] += (int)adj[i].size();
        for (int j : adj[i]) {
            revadj[j].push_back(i);
        }
    }

    queue<int> q;
    for (int i = 0; i < V; i++) {
        if (outdeg[i] == 0) q.push(i);
    }

    vector<int> ans;
    while (!q.empty()) {
        int node = q.front();
        q.pop();
        ans.push_back(node);
        for (int v : revadj[node]) {
            outdeg[v]--;
            if (outdeg[v] == 0) q.push(v);
        }
    }

    sort(ans.begin(), ans.end());
    return ans;
 }
};

class Solution {
public:
    int countPalSubseq(const string& s) {
        int n = s.size();
        if (n == 0) return 0;
        // dp[i][j] = number of non-empty palindromic subsequences in s[i..j]
        // (counts ALL palindromic subsequences, not just distinct ones)
        vector<vector<long long>> dp(n, vector<long long>(n, 0));
        for (int i = 0; i < n; i++) dp[i][i] = 1;
        for (int len = 2; len <= n; len++) {
            for (int i = 0; i + len - 1 < n; i++) {
                int j = i + len - 1;
                if (s[i] == s[j]) {
                    dp[i][j] = dp[i + 1][j] + dp[i][j - 1] + 1;
                } else {
                    dp[i][j] = dp[i + 1][j] + dp[i][j - 1] - dp[i + 1][j - 1];
                }
            }
        }
        return (int)dp[0][n - 1];
    }
};

class Solution {
  public:
    int findNumberOfComponent(int V, vector<vector<int>> &edges) {
        vector<vector<int>> adj(V);
        for (auto &e : edges) {
            int a = e[0], b = e[1];
            if (a < 0 || a >= V || b < 0 || b >= V) continue;
            adj[a].push_back(b);
            adj[b].push_back(a);
        }
        vector<char> vis(V, 0);
        int comp = 0;
        for (int i = 0; i < V; i++) {
            if (!vis[i]) {
                comp++;
                queue<int> q;
                q.push(i);
                vis[i] = 1;
                while (!q.empty()) {
                    int u = q.front(); q.pop();
                    for (int w : adj[u]) {
                        if (!vis[w]) { vis[w] = 1; q.push(w); }
                    }
                }
            }
        }
        return comp;
    }
};

class Solution {
public:
    void insert(vector<int>& nums, int i) {
        if (i <= 0) return;
        if (nums[i - 1] > nums[i]) {
            swap(nums[i - 1], nums[i]);
            insert(nums, i - 1);
        }
    }
    void sortRec(vector<int>& nums, int i) {
        if (i >= (int)nums.size()) return;
        insert(nums, i);
        sortRec(nums, i + 1);
    }
    vector<int> insertionSort(vector<int>& nums) {
        sortRec(nums, 1);
        return nums;
    }
};

class Solution {
public:
    vector<int> getFloorAndCeil(vector<int> nums, int x) {
        int n = nums.size();
        int floorVal = -1, ceilVal = -1;
        // floor: largest element <= x
        {
            int lo = 0, hi = n - 1;
            while (lo <= hi) {
                int mid = lo + (hi - lo) / 2;
                if (nums[mid] <= x) {
                    floorVal = nums[mid];
                    lo = mid + 1;
                } else {
                    hi = mid - 1;
                }
            }
        }
        // ceil: smallest element >= x
        {
            int lo = 0, hi = n - 1;
            while (lo <= hi) {
                int mid = lo + (hi - lo) / 2;
                if (nums[mid] >= x) {
                    ceilVal = nums[mid];
                    hi = mid - 1;
                } else {
                    lo = mid + 1;
                }
            }
        }
        return {floorVal, ceilVal};
    }
};

class Solution {
public:
    int majorityElement(vector<int>& nums) {
        int count = 0, candidate = 0;
        for (int x : nums) {
            if (count == 0) candidate = x;
            if (x == candidate) count++;
            else count--;
        }
        return candidate;
    }
};

class Solution{
public:
    int stockBuySell(vector<int> arr, int n){
        if(n <= 1) return 0;
        int minPrice = arr[0];
        int maxProfit = 0;
        for(int i = 1; i < n; i++){
            maxProfit = max(maxProfit, arr[i] - minPrice);
            minPrice = min(minPrice, arr[i]);
        }
        return maxProfit;
    }
};

class Solution {
public:
    string minWindow(string s, string t) {
        if (t.empty() || s.size() < t.size()) return "";
        vector<int> need(128, 0);
        for (char c : t) need[(unsigned char)c]++;
        int required = (int)t.size();
        int left = 0, minLen = INT_MAX, minStart = 0;
        for (int right = 0; right < (int)s.size(); right++) {
            if (need[(unsigned char)s[right]] > 0) required--;
            need[(unsigned char)s[right]]--;
            while (required == 0) {
                if (right - left + 1 < minLen) {
                    minLen = right - left + 1;
                    minStart = left;
                }
                need[(unsigned char)s[left]]++;
                if (need[(unsigned char)s[left]] > 0) required++;
                left++;
            }
        }
        return minLen == INT_MAX ? "" : s.substr(minStart, minLen);
    }
};

class Solution{
public:
    bool equalPartition(int n, vector<int> arr) {
        long long total = 0;
        for (int i = 0; i < n; i++) total += arr[i];
        if (total % 2 != 0) return false;
        long long target = total / 2;
        vector<char> dp(target + 1, 0);
        dp[0] = 1;
        for (int i = 0; i < n; i++) {
            long long v = arr[i];
            for (long long j = target; j >= v; j--) {
                if (dp[j - v]) dp[j] = 1;
            }
        }
        return dp[target] != 0;
    }
};

class Solution {
  public:
   int count(vector<int>&coins, int N, int amount) {
        const int MOD = 1e9 + 7;
        vector<long long> dp(amount + 1, 0);
        dp[0] = 1;
        for (int i = 0; i < N; i++) {
            for (int a = coins[i]; a <= amount; a++) {
                dp[a] = (dp[a] + dp[a - coins[i]]) % MOD;
            }
        }
        return (int)dp[amount];
    }
};

class Solution {
public:
    double myPow(double x, int n) {
        long long nn = n;            // promote to avoid overflow on abs of INT_MIN
        bool neg = nn < 0;
        if (neg) nn = -nn;
        double res = 1.0;
        double base = x;
        while (nn > 0) {
            if (nn & 1LL) res = res * base;
            base = base * base;
            nn >>= 1;
        }
        return neg ? 1.0 / res : res;
    }
};

class Solution {
public:
    double myPow(double x, int n) {
        long long nn = n;
        bool neg = false;
        if (nn < 0) { neg = true; nn = -nn; }
        double ans = 1.0;
        double base = x;
        while (nn > 0) {
            if (nn & 1LL) ans *= base;
            base *= base;
            nn >>= 1;
        }
        if (neg) ans = 1.0 / ans;
        return ans;
    }
};

class Solution {
public:
    double fractionalKnapsack(vector<long long>& val, vector<long long>& wt, long long capacity) {
        int n = val.size();
        // sort indices by value/weight ratio descending
        vector<int> idx(n);
        for (int i = 0; i < n; i++) idx[i] = i;
        sort(idx.begin(), idx.end(), [&](int a, int b) {
            // val[a]/wt[a] > val[b]/wt[b]  <=>  val[a]*wt[b] > val[b]*wt[a]
            return (long double)val[a] * wt[b] > (long double)val[b] * wt[a];
        });
        long double total = 0.0L;
        long long remaining = capacity;
        for (int k = 0; k < n && remaining > 0; k++) {
            int i = idx[k];
            if (wt[i] <= remaining) {
                total += (long double)val[i];
                remaining -= wt[i];
            } else {
                total += (long double)val[i] * ((long double)remaining / (long double)wt[i]);
                remaining = 0;
            }
        }
        return (double)total;
    }
};

class Solution{
    public:
    bool checkSubsequenceSum(vector<int>& nums, int k) {
        int n = nums.size();
        // Subset-sum DP: dp[s] = true if some subsequence sums to s.
        vector<char> dp(k + 1, 0);
        dp[0] = 1;
        for (int i = 0; i < n; i++) {
            int v = nums[i];
            if (v > k) continue; // positive values only (1 <= nums[i]), can't help reach k if > k
            for (int s = k; s >= v; s--) {
                if (dp[s - v]) dp[s] = 1;
            }
        }
        return dp[k] != 0;
    }
};

class Solution {
public:
    double median(vector<int> &arr1, vector<int> &arr2) {
        // Merge two sorted arrays (m + n <= 2000), pick the middle element(s).
        int n = (int)arr1.size();
        int m = (int)arr2.size();
        int total = n + m;
        int idx2 = total / 2;        // upper middle (even) / exact middle (odd)
        int idx1 = (total - 1) / 2;  // lower middle
        int i = 0, j = 0, cnt = 0;
        long long e1 = 0, e2 = 0;
        while (i < n || j < m) {
            int cur;
            if (j >= m || (i < n && arr1[i] <= arr2[j])) {
                cur = arr1[i++];
            } else {
                cur = arr2[j++];
            }
            if (cnt == idx1) e1 = cur;
            if (cnt == idx2) { e2 = cur; break; }
            cnt++;
        }
        return (e1 + e2) / 2.0;
    }
};

