class Solution {
public:
    vector<int> topKFrequent(const vector<int>& nums, int k) {
        unordered_map<int,int> freq;
        for (int x : nums) freq[x]++;
        int n = nums.size();
        vector<vector<int>> buckets(n + 1);
        for (auto& p : freq) buckets[p.second].push_back(p.first);
        vector<int> result;
        for (int f = n; f >= 1 && (int)result.size() < k; f--) {
            for (int val : buckets[f]) {
                result.push_back(val);
                if ((int)result.size() == k) break;
            }
        }
        sort(result.begin(), result.end());
        return result;
    }
};

class Solution{
public:
    vector<int> dijkstra(int V, vector<vector<int>> edges, int S) {
        vector<vector<pair<int,int>>> adj(V);
        for (auto &e : edges) {
            int u = e[0], v = e[1], w = e[2];
            adj[u].push_back({v, w});
            adj[v].push_back({u, w});
        }
        vector<int> dist(V, 1000000000);
        priority_queue<pair<int,int>, vector<pair<int,int>>, greater<pair<int,int>>> pq;
        dist[S] = 0;
        pq.push({0, S});
        while (!pq.empty()) {
            auto [d, u] = pq.top();
            pq.pop();
            if (d > dist[u]) continue;
            for (auto &pr : adj[u]) {
                int v = pr.first, w = pr.second;
                if (d + w < dist[v]) {
                    dist[v] = d + w;
                    pq.push({dist[v], v});
                }
            }
        }
        return dist;
    }
};

class Solution{

  public:
	int minDifference(vector<int>&arr, int n)  {
		int totalSum = 0;
		for(int i = 0; i < n; i++) totalSum += arr[i];

		// dp[s] = true if some subset of arr can sum to s
		vector<char> dp(totalSum + 1, false);
		dp[0] = true;
		for(int i = 0; i < n; i++){
			for(int s = totalSum; s >= arr[i]; s--){
				if(dp[s - arr[i]]) dp[s] = true;
			}
		}

		int ans = INT_MAX;
		for(int s = 0; s <= totalSum / 2; s++){
			if(dp[s]) ans = min(ans, abs((totalSum - s) - s));
		}
		return ans;
	}
};

class Solution {
public:	
    vector<vector<int> > powerSet(vector<int>& nums) {
        int n = nums.size();
        vector<vector<int>> ans;
        for (int mask = 0; mask < (1 << n); mask++) {
            vector<int> subset;
            for (int i = 0; i < n; i++) {
                if (mask & (1 << i)) {
                    subset.push_back(nums[i]);
                }
            }
            ans.push_back(subset);
        }
        return ans;
    }
};

class Solution {
public:
    int maxSumAfterPartitioning(vector<int>& arr, int k) {
        int n = arr.size();
        vector<long long> dp(n + 1, 0);
        for (int i = 1; i <= n; i++) {
            long long maxVal = 0;
            long long best = LLONG_MIN;
            for (int len = 1; len <= k && len <= i; len++) {
                int idx = i - len; // arr[idx] is the leftmost element of this block
                maxVal = max(maxVal, (long long)arr[idx]);
                long long cand = dp[idx] + maxVal * (long long)len;
                best = max(best, cand);
            }
            dp[i] = best;
        }
        return (int)dp[n];
    }
};

