            } else {
                j++;
            }
        }
        return count;
    }
};

class Solution {
public:
    int connectSticks(vector<int>& sticks) {
        priority_queue<long long, vector<long long>, greater<long long>> pq;
        for (int s : sticks) pq.push((long long)s);
        long long total = 0;
        while (pq.size() > 1) {
            long long a = pq.top(); pq.pop();
            long long b = pq.top(); pq.pop();
            long long cost = a + b;
            total += cost;
            pq.push(cost);
        }
        return (int)total;
    }
};

class Solution{
public:
    bool isBipartite(int V, vector<vector<int>> edges)  {
        vector<vector<int>> adj(V);
        for (auto &e : edges) {
            int u = e[0], v = e[1];
            adj[u].push_back(v);
            adj[v].push_back(u);
        }
        vector<int> color(V, 0); // 0 = uncolored, 1 / -1 = two colors
        for (int i = 0; i < V; i++) {
            if (color[i] == 0) {
                // BFS to avoid deep recursion for large V
                queue<int> q;
                q.push(i);
                color[i] = 1;
                while (!q.empty()) {
                    int node = q.front(); q.pop();
                    for (int nb : adj[node]) {
                        if (color[nb] == 0) {
                            color[nb] = -color[node];
                            q.push(nb);
                        } else if (color[nb] == color[node]) {
                            return false;
                        }
                    }
                }
            }
        }
        return true;
    }
};

class Solution {
    public:
        int maxCoins(vector<int>& nums){
            int n = nums.size();
            vector<int> a(n + 2);
            a[0] = 1;
            a[n + 1] = 1;
            for (int i = 0; i < n; i++) a[i + 1] = nums[i];
            // dp[i][j] = max coins bursting all balloons in open interval (i, j)
            vector<vector<long long>> dp(n + 2, vector<long long>(n + 2, 0));
            for (int len = 2; len <= n + 1; len++) {
                for (int i = 0; i + len <= n + 1; i++) {
                    int j = i + len;
                    long long best = 0;
                    for (int k = i + 1; k < j; k++) {
                        long long coins = (long long)a[i] * a[k] * a[j] + dp[i][k] + dp[k][j];
                        best = max(best, coins);
                    }
                    dp[i][j] = best;
                }
            }
            return (int)dp[0][n + 1];
        }
};

class Solution{
public:
    int solve(int n, vector<vector<int>> &Edge){
        // To connect n nodes we need at least n-1 edges. If fewer, impossible.
        if ((int)Edge.size() < n - 1) return -1;
        vector<int> parent(n), sz(n, 1);
        for (int i = 0; i < n; i++) parent[i] = i;
        function<int(int)> find = [&](int x) {
            while (parent[x] != x) { parent[x] = parent[parent[x]]; x = parent[x]; }
            return x;
        };
        for (auto &e : Edge) {
            int u = e[0], v = e[1];
            int pu = find(u), pv = find(v);
            if (pu == pv) continue;
            if (sz[pu] < sz[pv]) swap(pu, pv);
            parent[pv] = pu;
            sz[pu] += sz[pv];
        }
        int comp = 0;
        for (int i = 0; i < n; i++) if (find(i) == i) comp++;
        return comp - 1;
    }
};

class Solution {
	public:
    	int minCut(string s){
            int n = s.size();
            if (n <= 1) return 0;
            vector<vector<bool>> isPal(n, vector<bool>(n, false));
            for (int i = 0; i < n; i++) isPal[i][i] = true;
            for (int len = 2; len <= n; len++) {
                for (int i = 0; i + len - 1 < n; i++) {
                    int j = i + len - 1;
                    if (s[i] == s[j]) {
                        if (len == 2) isPal[i][j] = true;
                        else isPal[i][j] = isPal[i+1][j-1];
                    }
                }
            }
            vector<int> dp(n+1, 0);
            dp[n] = -1;
            for (int i = n-1; i >= 0; i--) {
                int best = INT_MAX;
                for (int j = i; j < n; j++) {
                    if (isPal[i][j]) {
                        int cost = 1 + dp[j+1];
                        best = min(best, cost);
                    }
                }
                dp[i] = best;
            }
            return dp[0];
	    }
};

class Solution {
  public: vector < int > findOrder(int N, vector < vector < int >> arr) {
    vector<int> indeg(N, 0);
    vector<vector<int>> adj(N);
    // arr[i] = [a, b] => must take b before a => edge b -> a, indegree of a increases
    for (auto &it : arr) {
        indeg[it[0]]++;
        adj[it[1]].push_back(it[0]);
    }
    queue<int> q;
    for (int i = 0; i < N; i++) if (indeg[i] == 0) q.push(i);
    vector<int> order;
    while (!q.empty()) {
        int node = q.front(); q.pop();
        order.push_back(node);
        for (int v : adj[node]) {
            if (--indeg[v] == 0) q.push(v);
        }
    }
    if ((int)order.size() == N) return order;
    return {};
  }
};

class Solution {
    public:
    vector<int> shortestPath(int N, int M, vector<vector<int>>& edges) {
        vector<vector<pair<int,int>>> adj(N);
        for (auto &e : edges) {
            adj[e[0]].push_back({e[1], e[2]});
        }
        const long long INF = 1e18;
        vector<long long> dist(N, INF);
        // Topological sort via iterative DFS (avoids recursion depth issues for large N)
        vector<bool> vis(N, false);
        vector<int> topo;
        for (int s = 0; s < N; s++) {
            if (vis[s]) continue;
            stack<pair<int,int>> st; // node, index into adj
            st.push({s, 0});
            vis[s] = true;
            while (!st.empty()) {
                auto &top = st.top();
                int node = top.first;
                int &idx = top.second;
                if (idx < (int)adj[node].size()) {
                    int nxt = adj[node][idx].first;
                    idx++;
                    if (!vis[nxt]) {
                        vis[nxt] = true;
                        st.push({nxt, 0});
                    }
                } else {
                    topo.push_back(node);
                    st.pop();
                }
            }
        }
        reverse(topo.begin(), topo.end());

        dist[0] = 0;
        for (int u : topo) {
            if (dist[u] == INF) continue; // unreachable, do not propagate
            for (auto &p : adj[u]) {
                int v = p.first;
                int w = p.second;
                if (dist[u] + w < dist[v]) {
                    dist[v] = dist[u] + w;
                }
            }
        }
        vector<int> ans(N);
        for (int i = 0; i < N; i++) {
            ans[i] = (dist[i] == INF) ? -1 : (int)dist[i];
        }
        return ans;
    }
};

class Solution {
public:
    void backtrack(int idx, int target, vector<int>& candidates, vector<int>& cur, vector<vector<int>>& res) {
        if (target == 0) {
            res.push_back(cur);
            return;
        }
        for (int i = idx; i < (int)candidates.size(); i++) {
            if (i > idx && candidates[i] == candidates[i-1]) continue;
            if (candidates[i] > target) break;
            cur.push_back(candidates[i]);
            backtrack(i + 1, target - candidates[i], candidates, cur, res);
            cur.pop_back();
        }
    }
    vector<vector<int> > combinationSum2(vector<int>& candidates, int target) {
        sort(candidates.begin(), candidates.end());
        vector<vector<int>> res;
        vector<int> cur;
        backtrack(0, target, candidates, cur, res);
        return res;
    }
};

class Solution{
private:
    void dfs(int node, vector<int> adj[], vector<int>& vis, vector<int>& st){
        vis[node] = 1;
        for(auto it : adj[node]){
            if(!vis[it]){
                dfs(it, adj, vis, st);
            }
        }
        st.push_back(node);
    }
public:
    vector<int> topoSort(int V, vector<int> adj[]){
        vector<int> vis(V, 0);
        vector<int> st;
        for(int i = 0; i < V; i++){
            if(!vis[i]){
                dfs(i, adj, vis, st);
            }
        }
        reverse(st.begin(), st.end());
        return st;
    }
};

