class Solution{
	public:
		bool anagramStrings(string& s,string t){
			if(s.size()!=t.size()) return false;
			int cnt[26]={0};
			for(char c: s) cnt[c-'a']++;
			for(char c: t) cnt[c-'a']--;
			for(int i=0;i<26;i++) if(cnt[i]!=0) return false;
			return true;
		}
};

class Solution {
public:
    string prefixToPostfix(const string& s) {
        auto isOperator = [](char c) {
            return c == '+' || c == '-' || c == '*' || c == '/' || c == '^';
        };
        stack<string> st;
        int n = (int)s.size();
        for (int i = n - 1; i >= 0; --i) {
            char c = s[i];
            if (isspace((unsigned char)c)) continue;
            if (isOperator(c)) {
                string a = st.empty() ? "" : st.top(); if (!st.empty()) st.pop();
                string b = st.empty() ? "" : st.top(); if (!st.empty()) st.pop();
                string combined = a + b + c;
                st.push(combined);
            } else {
                st.push(string(1, c));
            }
        }
        return st.empty() ? "" : st.top();
    }
};

class Solution {
public:
    bool isValid(string str) {
        stack<char> st;
        for (char c : str) {
            if (c == '(' || c == '{' || c == '[') {
                st.push(c);
            } else {
                if (st.empty()) return false;
                char top = st.top();
                if ((c == ')' && top == '(') ||
                    (c == '}' && top == '{') ||
                    (c == ']' && top == '[')) {
                    st.pop();
                } else {
                    return false;
                }
            }
        }
        return st.empty();
    }
};

class Solution{
public:
    int CheapestFlight(int n, vector<vector<int>> &flights,
                       int src, int dst, int K) {
        vector<vector<pair<int,int>>> adj(n);
        for (auto &f : flights) adj[f[0]].push_back({f[1], f[2]});
        vector<int> dis(n, INT_MAX);
        dis[src] = 0;
        queue<pair<int,int>> q; // {node, cost}
        q.push({src, 0});
        int stops = 0;
        while (!q.empty() && stops <= K) {
            int size = q.size();
            while (size--) {
                auto [u, ucost] = q.front(); q.pop();
                for (auto &[v, w] : adj[u]) {
                    if (ucost + w < dis[v]) {
                        dis[v] = ucost + w;
                        q.push({v, dis[v]});
                    }
                }
            }
            stops++;
        }
        if (dis[dst] == INT_MAX) return -1;
        return dis[dst];
    }
};

class Solution {
public:
    vector<int> findMissingRepeatingNumbers(vector<int> nums) {
        long long n = (long long)nums.size();
        // Sum and sum of squares approach (does not modify the array)
        long long SN = n * (n + 1) / 2;
        long long S2N = n * (n + 1) * (2 * n + 1) / 6;
        long long S = 0, S2 = 0;
        for (int x : nums) {
            S += (long long)x;
            S2 += (long long)x * (long long)x;
        }
        // Let repeating = A, missing = B
        // S  - SN  = A - B
        // S2 - S2N = A^2 - B^2 = (A-B)(A+B)
        long long val1 = S - SN;      // A - B
        long long val2 = S2 - S2N;    // A^2 - B^2
        long long sum = val2 / val1;  // A + B
        long long A = (val1 + sum) / 2;
        long long B = A - val1;
        return {(int)A, (int)B};
    }
};

class Solution {
public:
    int uniquePaths(int m, int n) {
        // Number of unique paths from top-left to bottom-right
        // moving only right/down = C(m+n-2, m-1).
        long long N = (long long)m + n - 2;
        long long r = min((long long)m - 1, (long long)n - 1);
        long long res = 1;
        for (long long i = 1; i <= r; i++) {
            res = res * (N - r + i) / i;
        }
        return (int)res;
    }
};

class Solution{
