            vector<vector<int>> ans;
            for(int q : queries){
                vector<int> factors;
                int x = q;
                for(int i = 2; (long long)i*i <= x; i++){
                    while(x % i == 0){
                        factors.push_back(i);
                        x /= i;
                    }
                }
                if(x > 1) factors.push_back(x);
                ans.push_back(factors);
            }
