            int mini = i;
            for (int j = i + 1; j < n; j++) {
                if (nums[j] < nums[mini]) mini = j;
            }
            swap(nums[i], nums[mini]);
        }
        return nums;
    }
};

class Solution {
public:
    void solve(int start, int k, int tar, vector<int>& temp, vector<vector<int>>& ans) {
        if (tar == 0 && (int)temp.size() == k) {
            ans.push_back(temp);
            return;
        }
        if ((int)temp.size() == k || tar <= 0) return;
        for (int i = start; i <= 9; i++) {
            if (i > tar) break;
            temp.push_back(i);
            solve(i + 1, k, tar - i, temp, ans);
            temp.pop_back();
        }
    }

    vector<vector<int> > combinationSum3(int k, int n) {
        vector<vector<int>> ans;
        vector<int> temp;
        solve(1, k, n, temp, ans);
        return ans;
    }
};

class Solution{
public:
    int minimumMultiplications(vector<int> &arr,
                               int start, int end) {
        const int MOD = 100000;
        if (start == end) return 0;
        vector<int> dist(MOD, -1);
        queue<int> q;
        dist[start] = 0;
        q.push(start);
        while (!q.empty()) {
            int node = q.front(); q.pop();
            int steps = dist[node];
            for (int x : arr) {
                int nxt = (int)((long long)node * x % MOD);
                if (dist[nxt] == -1) {
                    dist[nxt] = steps + 1;
                    if (nxt == end) return steps + 1;
                    q.push(nxt);
                }
            }
        }
        return -1;
    }
};

