class Solution{
public:
    bool isCycle(int V, vector<int> adj[]) {
        vector<int> vis(V, 0);
        for (int start = 0; start < V; start++) {
            if (vis[start]) continue;
            queue<pair<int,int>> q;
            q.push({start, -1});
            vis[start] = 1;
            while (!q.empty()) {
                int node = q.front().first;
                int parent = q.front().second;
                q.pop();
                for (int it : adj[node]) {
                    if (!vis[it]) {
                        vis[it] = 1;
                        q.push({it, node});
                    } else if (it != parent) {
                        return true;
                    }
                }
            }
        }
        return false;
    }
};

class Solution {
