class Solution{
    public:
        vector<int> primesInRange(vector<vector<int>>& queries){
            const int MAXN = 100000;
            vector<int> prefix(MAXN + 1, 0);
            vector<bool> isComposite(MAXN + 1, false);
            isComposite[0] = isComposite[1] = true; // 0 and 1 are not prime
            for (long long i = 2; i <= MAXN; ++i) {
                if (!isComposite[i]) {
                    for (long long j = i * i; j <= MAXN; j += i)
                        isComposite[j] = true;
                }
            }
            // prefix[k] = number of primes in [0..k]
            for (int i = 1; i <= MAXN; ++i) {
                prefix[i] = prefix[i - 1] + (isComposite[i] ? 0 : 1);
            }
            vector<int> result;
            result.reserve(queries.size());
            for (auto &q : queries) {
                int l = q[0], r = q[1];
                if (l < 0) l = 0;
                int countUpToR = (r >= 0) ? prefix[r] : 0;
                int countUpToLm1 = (l >= 1) ? prefix[l - 1] : 0;
                result.push_back(countUpToR - countUpToLm1);
            }
            return result;
        }
};

class Solution {
public:
    int maxChocolates(vector<vector<int>>& g) {
        int r = g.size();
        if (r == 0) return 0;
        int c = g[0].size();
        const long long NEG = LLONG_MIN / 4;
        // next[j1][j2] = best collectable from row i+1 onward with Alice at j1, Bob at j2
        vector<vector<long long>> next(c, vector<long long>(c, 0));
        // base case: last row
        for (int j1 = 0; j1 < c; j1++) {
            for (int j2 = 0; j2 < c; j2++) {
                if (j1 == j2) next[j1][j2] = g[r-1][j1];
                else next[j1][j2] = (long long)g[r-1][j1] + g[r-1][j2];
            }
        }
        for (int i = r - 2; i >= 0; i--) {
            vector<vector<long long>> cur(c, vector<long long>(c, 0));
            for (int j1 = 0; j1 < c; j1++) {
                for (int j2 = 0; j2 < c; j2++) {
                    long long best = NEG;
                    for (int dj1 = -1; dj1 <= 1; dj1++) {
                        for (int dj2 = -1; dj2 <= 1; dj2++) {
                            int nj1 = j1 + dj1, nj2 = j2 + dj2;
                            if (nj1 < 0 || nj1 >= c || nj2 < 0 || nj2 >= c) continue;
                            best = max(best, next[nj1][nj2]);
                        }
                    }
                    long long val = (j1 == j2) ? g[i][j1] : (long long)g[i][j1] + g[i][j2];
                    cur[j1][j2] = val + best;
                }
            }
            next = cur;
        }
        return (int)next[0][c-1];
    }
};

