class Solution {
public:
    void maxHeapify(vector<int>& nums, int i, int n) {
        int largest = i;
        int left = 2 * i + 1;
        int right = 2 * i + 2;
        if (left < n && nums[left] > nums[largest]) largest = left;
        if (right < n && nums[right] > nums[largest]) largest = right;
        if (largest != i) {
            swap(nums[i], nums[largest]);
            maxHeapify(nums, largest, n);
        }
    }
    vector<int> minToMaxHeap(vector<int> nums) {
        int n = (int)nums.size();
        for (int i = n / 2 - 1; i >= 0; i--) {
            maxHeapify(nums, i, n);
        }
        return nums;
    }
};

class Solution {
public:
    int myAtoi(string input) {
        int n = (int)input.size();
        int i = 0;
        // skip leading whitespace
        while (i < n && input[i] == ' ') i++;
        if (i == n) return 0;
        int sign = 1;
        if (input[i] == '+' || input[i] == '-') {
            if (input[i] == '-') sign = -1;
            i++;
        }
        long long ans = 0;
        while (i < n && input[i] >= '0' && input[i] <= '9') {
            ans = ans * 10 + (input[i] - '0');
            if (sign == 1 && ans > 2147483647LL) return 2147483647;
            if (sign == -1 && -ans < -2147483648LL) return -2147483648;
            i++;
        }
        ans = sign * ans;
        if (ans > 2147483647LL) return 2147483647;
        if (ans < -2147483648LL) return -2147483648;
        return (int)ans;
    }
};

class Solution {
public:
    int networkDelayTime(vector<vector<int>>& times, int n, int k) {
        vector<vector<pair<int,int>>> adj(n + 1);
        for (auto& e : times) {
            adj[e[0]].push_back({e[1], e[2]});
        }
        priority_queue<pair<long long,int>, vector<pair<long long,int>>, greater<pair<long long,int>>> pq;
        vector<long long> dis(n + 1, LLONG_MAX);
        dis[k] = 0;
        pq.push({0, k});
        while (!pq.empty()) {
            auto [uwt, u] = pq.top();
            pq.pop();
            if (uwt > dis[u]) continue;
            for (auto& [v, vwt] : adj[u]) {
                if (dis[v] > uwt + vwt) {
                    dis[v] = uwt + vwt;
                    pq.push({dis[v], v});
                }
            }
        }
        long long ans = 0;
        for (int i = 1; i <= n; i++) {
            if (dis[i] == LLONG_MAX) return -1;
            ans = max(ans, dis[i]);
        }
        return (int)ans;
    }
};

class Solution {
public:
    int singleNonDuplicate(vector<int> &nums) {
        int n = nums.size();
        if (n == 1) return nums[0];
        if (nums[0] != nums[1]) return nums[0];
        if (nums[n - 1] != nums[n - 2]) return nums[n - 1];
        int low = 1, high = n - 2;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (nums[mid] != nums[mid - 1] && nums[mid] != nums[mid + 1]) {
                return nums[mid];
            }
            if ((mid % 2 == 0 && nums[mid] == nums[mid + 1]) ||
                (mid % 2 == 1 && nums[mid] == nums[mid - 1])) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return -1;
    }
};

class Solution {
  public:
   int countPartitions(int n, int diff, vector<int>& arr) {
        const int mod = 1e9 + 7;
        long long totalSum = 0;
        for (int x : arr) totalSum += x;
        // S1 + S2 = totalSum, S1 - S2 = diff  =>  S2 = (totalSum - diff) / 2
        if (totalSum - diff < 0 || (totalSum - diff) % 2 != 0) return 0;
        long long target = (totalSum - diff) / 2;
        // dp[j] = number of subsets (using processed elements) with sum == j
        // Zeros are handled by the base case so an element equal to 0 can be
        // placed in either subset, doubling the count.
        vector<long long> dp(target + 1, 0);
        if (arr[0] == 0) {
            dp[0] = 2; // include or exclude => both yield sum 0
        } else {
            dp[0] = 1;
            if (arr[0] <= target) dp[arr[0]] = (dp[arr[0]] + 1) % mod;
        }
        for (int i = 1; i < n; i++) {
            vector<long long> cur(target + 1, 0);
            for (long long j = 0; j <= target; j++) {
                long long notTake = dp[j];
                long long take = 0;
                if (arr[i] <= j) take = dp[j - arr[i]];
                cur[j] = (notTake + take) % mod;
            }
            dp = cur;
        }
        return (int)(dp[target] % mod);
    }
};

