class Solution{
public:
    vector<int> maxSlidingWindow(vector<int> &arr, int k) {
        int n = arr.size();
        vector<int> ans;
        deque<int> dq; // stores indices; front holds index of current max
        for (int i = 0; i < n; i++) {
            // remove indices that fall outside the window
            if (!dq.empty() && dq.front() <= i - k) dq.pop_front();
            // maintain a decreasing deque of values
            while (!dq.empty() && arr[dq.back()] <= arr[i]) dq.pop_back();
            dq.push_back(i);
            if (i >= k - 1) ans.push_back(arr[dq.front()]);
        }
        return ans;
    }
};

class Solution {
public:
    void merge(vector<int>& nums, int low, int mid, int high) {
        vector<int> temp;
        int left = low, right = mid + 1;
        while (left <= mid && right <= high) {
            if (nums[left] <= nums[right]) temp.push_back(nums[left++]);
            else temp.push_back(nums[right++]);
        }
        while (left <= mid) temp.push_back(nums[left++]);
        while (right <= high) temp.push_back(nums[right++]);
        for (int i = low; i <= high; i++) nums[i] = temp[i - low];
    }
    void ms(vector<int>& nums, int low, int high) {
        if (low >= high) return;
        int mid = (low + high) / 2;
        ms(nums, low, mid);
        ms(nums, mid + 1, high);
        merge(nums, low, mid, high);
    }
    vector<int> mergeSort(vector<int>& nums) {
        ms(nums, 0, (int)nums.size() - 1);
        return nums;
    }
};

class Solution {
public:
    int findMaximumXOR(vector<int>& nums) {
        int maxNum = 0;
        for (int x : nums) maxNum = max(maxNum, x);
        int highBit = (maxNum == 0) ? 0 : (31 - __builtin_clz((unsigned)maxNum));
        int maxXor = 0, mask = 0;
        for (int i = highBit; i >= 0; --i) {
            mask |= (1 << i);
            unordered_set<int> prefixes;
            for (int x : nums) prefixes.insert(x & mask);
            int candidate = maxXor | (1 << i);
            bool found = false;
            for (int p : prefixes) {
                if (prefixes.count(candidate ^ p)) { found = true; break; }
            }
            if (found) maxXor = candidate;
        }
        return maxXor;
    }
};

class Solution {
public:
    int frogJump(vector<int>& heights) {
        int n = heights.size();
        if (n <= 1) return 0;
        vector<int> dp(n, 0);
        dp[0] = 0;
        dp[1] = abs(heights[1] - heights[0]);
        for (int i = 2; i < n; i++) {
            int oneStep = dp[i-1] + abs(heights[i] - heights[i-1]);
            int twoStep = dp[i-2] + abs(heights[i] - heights[i-2]);
            dp[i] = min(oneStep, twoStep);
        }
        return dp[n-1];
    }
};

class Solution {
public:
    int longestStringChain(vector<string>& words) {
        sort(words.begin(), words.end(), [](const string& a, const string& b){
            return a.size() < b.size();
        });
        unordered_map<string,int> dp;
        int best = 0;
        for (const string& w : words) {
            int cur = 1; // the word itself is a chain of length 1
            for (int i = 0; i < (int)w.size(); ++i) {
                string pred = w.substr(0, i) + w.substr(i + 1);
                auto it = dp.find(pred);
                if (it != dp.end()) {
                    cur = max(cur, it->second + 1);
                }
            }
            auto it = dp.find(w);
            if (it == dp.end() || it->second < cur) dp[w] = cur;
            best = max(best, dp[w]);
        }
        return best;
    }
};

class Solution{
public:
    int kosaraju(int V, vector<int> adj[]){
        // Step 1: order vertices by finish time (iterative DFS to avoid stack overflow)
        vector<bool> vis(V, false);
        vector<int> order;
        order.reserve(V);
        for (int s = 0; s < V; s++) {
            if (vis[s]) continue;
            stack<pair<int,int>> st; // {node, next child index}
            st.push({s, 0});
            vis[s] = true;
            while (!st.empty()) {
                auto &top = st.top();
                int node = top.first;
                if (top.second < (int)adj[node].size()) {
                    int v = adj[node][top.second];
                    top.second++;
                    if (!vis[v]) {
                        vis[v] = true;
                        st.push({v, 0});
                    }
                } else {
                    order.push_back(node);
                    st.pop();
                }
            }
        }

        // Step 2: build reverse graph
        vector<vector<int>> radj(V);
        for (int i = 0; i < V; i++) {
            for (int j : adj[i]) {
                radj[j].push_back(i);
            }
        }

        // Step 3: process in reverse finish order on reverse graph
        fill(vis.begin(), vis.end(), false);
        int scc = 0;
        for (int idx = V - 1; idx >= 0; idx--) {
            int node = order[idx];
            if (vis[node]) continue;
            scc++;
            stack<int> st;
            st.push(node);
            vis[node] = true;
            while (!st.empty()) {
                int cur = st.top(); st.pop();
                for (int v : radj[cur]) {
                    if (!vis[v]) {
                        vis[v] = true;
                        st.push(v);
                    }
                }
            }
        }
        return scc;
    }
};

