class Solution {
public:
	int findCity(int n, int m, vector<vector<int>>& edges,
	             int distanceThreshold) {
		const long long INF = 1e15;
		vector<vector<long long>> dist(n, vector<long long>(n, INF));
		for (int i = 0; i < n; i++) dist[i][i] = 0;
		for (auto &e : edges) {
			int u = e[0], v = e[1];
			long long w = e[2];
			if (w < dist[u][v]) { dist[u][v] = w; dist[v][u] = w; }
		}
		for (int k = 0; k < n; k++)
			for (int i = 0; i < n; i++)
				for (int j = 0; j < n; j++)
					if (dist[i][k] + dist[k][j] < dist[i][j])
						dist[i][j] = dist[i][k] + dist[k][j];

		int ansCity = -1, minCount = INT_MAX;
		for (int i = 0; i < n; i++) {
			int cnt = 0;
			for (int j = 0; j < n; j++)
				if (i != j && dist[i][j] <= distanceThreshold) cnt++;
			if (cnt <= minCount) { minCount = cnt; ansCity = i; }
		}
		return ansCity;
	}
};

class Solution {
public:
    int prec(char c) {
        if (c == '*' || c == '/') return 2;
        if (c == '+' || c == '-') return 1;
        return 0;
    }
    // Standard infix->postfix used on the reversed (paren-swapped) string.
    // For left-associative operators in the reversed scan we pop only on
    // STRICTLY greater precedence (>), then reverse the result to get prefix.
    string toPostfix(const string& s) {
        string ans = "";
        stack<char> st;
        for (char c : s) {
            if (isalnum((unsigned char)c)) {
                ans.push_back(c);
            } else if (c == '(') {
                st.push(c);
            } else if (c == ')') {
                while (!st.empty() && st.top() != '(') {
                    ans.push_back(st.top());
                    st.pop();
                }
                if (!st.empty()) st.pop(); // discard '('
            } else {
                while (!st.empty() && st.top() != '(' && prec(st.top()) > prec(c)) {
                    ans.push_back(st.top());
                    st.pop();
                }
                st.push(c);
            }
        }
        while (!st.empty()) {
            ans.push_back(st.top());
            st.pop();
        }
        return ans;
    }
    string infixToPrefix(const string& s) {
        // Reverse the expression and swap parentheses.
        string rev(s.rbegin(), s.rend());
        for (char& c : rev) {
            if (c == '(') c = ')';
            else if (c == ')') c = '(';
        }
        // Convert reversed expression to postfix, then reverse to obtain prefix.
        string post = toPostfix(rev);
        reverse(post.begin(), post.end());
        return post;
    }
};

