        while (temp > 0) {
            reversed = reversed * 10 + temp % 10;
            temp /= 10;
        }
        return reversed == original;
    }
};

class Solution {
public:
  int smallestDivisor(vector<int> &nums, int limit) {
      int lo = 1;
      int hi = 0;
      for (int x : nums) hi = max(hi, x);
      int ans = hi;
      while (lo <= hi) {
          int mid = lo + (hi - lo) / 2;
          long long sum = 0;
          for (int x : nums) {
              sum += (long long)(x + mid - 1) / mid; // ceiling division
          }
          if (sum <= (long long)limit) {
              ans = mid;
              hi = mid - 1;
          } else {
              lo = mid + 1;
          }
      }
      return ans;
  }
};

class Solution{
    public:
        vector <int> search(string pat, string txt) {
            vector<int> result;
            int n = txt.size();
            int m = pat.size();
            if (m == 0 || m > n) return result;

            const long long MOD = 1000000007LL;
            const long long BASE = 256LL;

            // precompute BASE^(m-1) % MOD for the rolling-hash removal step
            long long h = 1;
            for (int i = 0; i < m - 1; i++) {
                h = (h * BASE) % MOD;
            }

            long long patHash = 0, txtHash = 0;
            for (int i = 0; i < m; i++) {
                patHash = (patHash * BASE + (unsigned char)pat[i]) % MOD;
                txtHash = (txtHash * BASE + (unsigned char)txt[i]) % MOD;
            }

            for (int i = 0; i <= n - m; i++) {
                if (patHash == txtHash) {
                    // verify character by character to guard against hash collisions
                    bool match = true;
                    for (int j = 0; j < m; j++) {
                        if (txt[i + j] != pat[j]) { match = false; break; }
                    }
                    if (match) result.push_back(i);
                }
                if (i < n - m) {
                    txtHash = (txtHash - ((unsigned char)txt[i] * h) % MOD + MOD) % MOD;
                    txtHash = (txtHash * BASE + (unsigned char)txt[i + m]) % MOD;
                }
            }
            return result;
        }
};

