        int n = adj.size();
        vector<int> vis(n, 0);
        int provinces = 0;
        for (int i = 0; i < n; i++) {
            if (!vis[i]) {
                provinces++;
                queue<int> q;
                q.push(i);
                vis[i] = 1;
                while (!q.empty()) {
                    int node = q.front(); q.pop();
                    for (int j = 0; j < n; j++) {
                        if (adj[node][j] == 1 && !vis[j]) {
                            vis[j] = 1;
                            q.push(j);
                        }
                    }
                }
            }
        }
        return provinces;
    }
};

class Solution {
  public:
    int editDistance(string start, string target) {
        int n = start.size(), m = target.size();
        vector<int> prev(m + 1, 0), cur(m + 1, 0);
        for (int j = 0; j <= m; j++) prev[j] = j;
        for (int i = 1; i <= n; i++) {
            cur[0] = i;
            for (int j = 1; j <= m; j++) {
                if (start[i - 1] == target[j - 1]) {
                    cur[j] = prev[j - 1];
                } else {
                    cur[j] = 1 + min({prev[j - 1], prev[j], cur[j - 1]});
                }
            }
            prev = cur;
        }
        return prev[m];
    }
};

class Solution {
public:
    int minFallingPathSum(vector<vector<int>>& matrix) {
        int m = matrix.size();
        int n = matrix[0].size();
        vector<long long> prev(n);
        for (int j = 0; j < n; j++) prev[j] = matrix[0][j];
        for (int i = 1; i < m; i++) {
            vector<long long> cur(n);
            for (int j = 0; j < n; j++) {
                long long best = prev[j];
                if (j - 1 >= 0) best = min(best, prev[j - 1]);
                if (j + 1 < n) best = min(best, prev[j + 1]);
                cur[j] = (long long)matrix[i][j] + best;
            }
            prev = cur;
        }
        long long ans = LLONG_MAX / 4;
        for (int j = 0; j < n; j++) ans = min(ans, prev[j]);
        return (int)ans;
    }
};

