class Solution {
	public:
		int minCost(int n, vector<int>& cuts){
			vector<int> arr;
			arr.push_back(0);
			for (int x : cuts) arr.push_back(x);
			arr.push_back(n);
			sort(arr.begin(), arr.end());
			int m = arr.size();
			// dp[i][j] = min cost to fully cut the segment between arr[i] and arr[j]
			// using only the cut points strictly inside that segment.
			vector<vector<long long>> dp(m, vector<long long>(m, 0));
			for (int len = 2; len < m; len++) {
				for (int i = 0; i + len < m; i++) {
					int j = i + len;
					long long best = LLONG_MAX;
					for (int k = i + 1; k < j; k++) {
						long long cost = (long long)(arr[j] - arr[i]) + dp[i][k] + dp[k][j];
						best = min(best, cost);
					}
					dp[i][j] = best;
				}
			}
			return (int)dp[0][m - 1];
		}
};

class Solution {
public:
	vector<int> bellman_ford(int V, vector<vector<int>>& edges, int S) {
		const int INF = 1e9;
		vector<int> dist(V, INF);
		dist[S] = 0;
		// Relax all edges V-1 times
		for (int i = 0; i < V - 1; i++) {
			for (auto &e : edges) {
				int u = e[0], v = e[1], w = e[2];
				if (dist[u] != INF && dist[u] + w < dist[v]) {
					dist[v] = dist[u] + w;
				}
			}
		}
		// One more pass to detect a negative cycle
		for (auto &e : edges) {
			int u = e[0], v = e[1], w = e[2];
			if (dist[u] != INF && dist[u] + w < dist[v]) {
				return {-1};
			}
		}
		return dist;
	}
};

class Solution{
	public:
	int MinimumCoins(vector<int>& coins, int amount) {
        int n = coins.size();
        const int INF = 1e9;
        vector<int> dp(amount + 1, INF);
        dp[0] = 0;
        for (int i = 0; i < n; i++) {
            for (int a = coins[i]; a <= amount; a++) {
                if (dp[a - coins[i]] != INF)
                    dp[a] = min(dp[a], dp[a - coins[i]] + 1);
            }
        }
        return dp[amount] >= INF ? -1 : dp[amount];
    }
};

class Solution{
