class Solution {
public:
    vector<string> generateBinaryStrings(int n) {
        vector<string> result;
        string cur;
        solve(0, n, cur, result);
        return result;
    }
private:
    void solve(int idx, int n, string &cur, vector<string> &result) {
        if (idx == n) {
            result.push_back(cur);
            return;
        }
        // Place '0' always (tried first to keep lexicographic order)
        cur.push_back('0');
        solve(idx + 1, n, cur, result);
        cur.pop_back();
        // Place '1' only if previous char is not '1'
        if (idx == 0 || cur[idx - 1] != '1') {
            cur.push_back('1');
            solve(idx + 1, n, cur, result);
            cur.pop_back();
        }
    }
};

class Solution {
  public:
    int findNumberOfComponent(int V, vector<vector<int>> &edges) {
        vector<int> parent(V), rnk(V, 0);
        for (int i = 0; i < V; i++) parent[i] = i;
        function<int(int)> find = [&](int x) {
            while (parent[x] != x) {
                parent[x] = parent[parent[x]];
                x = parent[x];
            }
            return x;
        };
        int components = V;
        for (auto &e : edges) {
            int a = e[0], b = e[1];
            int ra = find(a), rb = find(b);
            if (ra != rb) {
                if (rnk[ra] < rnk[rb]) swap(ra, rb);
                parent[rb] = ra;
                if (rnk[ra] == rnk[rb]) rnk[ra]++;
                components--;
            }
        }
        return components;
    }
};

class Solution{
public:
    int stockBuySell(vector<int> arr, int n, int fee){
        // DP on stocks with transaction fee (fee charged on each sell).
        // notHold = max profit with no stock held at end of the day.
        // hold    = max profit while holding a stock at end of the day.
        long long notHold = 0;
        long long hold = LLONG_MIN / 4; // impossible to hold before any buy
        for(int i = 0; i < n; i++){
            long long prevNotHold = notHold;
            long long prevHold = hold;
            // buy today: pay the price
            hold = max(prevHold, prevNotHold - (long long)arr[i]);
            // sell today: receive price minus transaction fee
            notHold = max(prevNotHold, prevHold + (long long)arr[i] - (long long)fee);
        }
        return (int)notHold;
    }
};

class Solution{
	public:
	int perfectSum(vector<int>&arr, int K){
	    const int MOD = 1e9 + 7;
	    int n = (int)arr.size();
	    // dp[j] = number of subsets with sum j (modulo MOD)
	    vector<long long> dp(K + 1, 0);
	    dp[0] = 1; // the empty subset has sum 0
	    for (int i = 0; i < n; i++) {
	        // iterate downwards so each element is used at most once
	        for (int j = K; j >= arr[i]; j--) {
	            dp[j] = (dp[j] + dp[j - arr[i]]) % MOD;
	        }
	    }
	    return (int)(dp[K] % MOD);
	}
};

class Solution {
