    vector<int> twoSum(vector<int>& nums, int target) {
        unordered_map<int,int> seen; // value -> first index
        for (int i = 0; i < (int)nums.size(); i++) {
            int need = target - nums[i];
            auto it = seen.find(need);
            if (it != seen.end()) {
                return {it->second, i};
            }
            seen[nums[i]] = i;
        }
        return {};
    }
};

class Solution{
public:
    int longestSubarray(vector<int> &nums, int k){
        unordered_map<long long, int> firstIdx; // prefix sum -> earliest index seen
        long long pref = 0;
        int ans = 0;
        int n = nums.size();
        for (int i = 0; i < n; i++) {
            pref += (long long)nums[i];
            if (pref == (long long)k) {
                ans = max(ans, i + 1);
            }
            long long need = pref - (long long)k;
            auto it = firstIdx.find(need);
            if (it != firstIdx.end()) {
                ans = max(ans, i - it->second);
            }
            if (firstIdx.find(pref) == firstIdx.end()) {
                firstIdx[pref] = i;
            }
        }
        return ans;
    }
};

