class Solution {
public:
    string findOrder(string dict[], int N, int K) {
        vector<vector<int>> adj(K);
        vector<int> indeg(K, 0);
        // avoid counting duplicate edges twice (would corrupt indegree)
        vector<set<int>> seen(K);

        for (int i = 1; i < N; i++) {
            string &a = dict[i - 1];
            string &b = dict[i];
            int len = min((int)a.size(), (int)b.size());
            int j = 0;
            bool foundDiff = false;
            for (; j < len; j++) {
                if (a[j] != b[j]) {
                    int u = a[j] - 'a';
                    int v = b[j] - 'a';
                    if (!seen[u].count(v)) {
                        seen[u].insert(v);
                        adj[u].push_back(v);
                        indeg[v]++;
                    }
                    foundDiff = true;
                    break;
                }
            }
            // Prefix violation: a longer string cannot come before its own prefix
            // e.g. "abc" before "ab" is inconsistent with any ordering.
            if (!foundDiff && a.size() > b.size()) {
                return "";
            }
        }

        // Kahn's algorithm (BFS topological sort)
        queue<int> q;
        for (int i = 0; i < K; i++) {
            if (indeg[i] == 0) q.push(i);
        }

        string ans = "";
        while (!q.empty()) {
            int node = q.front();
            q.pop();
            ans += (char)(node + 'a');
            for (int v : adj[node]) {
                indeg[v]--;
                if (indeg[v] == 0) q.push(v);
            }
        }

        // If not all K characters were emitted, there is a cycle -> inconsistent.
        if ((int)ans.size() < K) return "";
        return ans;
    }
};

class Solution
{
    public:
   int unboundedKnapsack(vector<int>& wt, vector<int>& val, int n, int W) {
       // dp[w] = max value achievable with capacity w (unbounded: infinite supply)
       vector<long long> dp(W + 1, 0);
       for (int i = 0; i < n; i++) {
           for (int w = wt[i]; w <= W; w++) {
               dp[w] = max(dp[w], dp[w - wt[i]] + (long long)val[i]);
           }
       }
       return (int)dp[W];
   }
};

class Solution {
public:
    vector<int> bubbleSort(vector<int>& nums) {
        int n = nums.size();
        for (int i = n - 1; i > 0; i--) {
            bool swapped = false;
            for (int j = 0; j < i; j++) {
                if (nums[j] > nums[j + 1]) {
                    swap(nums[j], nums[j + 1]);
                    swapped = true;
                }
            }
            if (!swapped) break;
        }
        return nums;
    }
};

class Solution{
public:
    bool isCycle(int V, vector<int> adj[]) {
        vector<bool> vis(V, false);
        for (int start = 0; start < V; start++) {
            if (vis[start]) continue;
            // BFS with parent tracking
            queue<pair<int,int>> q; // {node, parent}
            q.push({start, -1});
            vis[start] = true;
            while (!q.empty()) {
                int node = q.front().first;
                int parent = q.front().second;
                q.pop();
                for (int adjNode : adj[node]) {
                    if (!vis[adjNode]) {
                        vis[adjNode] = true;
                        q.push({adjNode, node});
                    } else if (adjNode != parent) {
                        return true;
                    }
                }
            }
        }
        return false;
    }
};

class Solution {
public:
    string completeString(vector<string>& nums) {
        struct TrieNode {
            TrieNode* children[26];
            bool end;
            TrieNode() {
                end = false;
                for (int i = 0; i < 26; i++) children[i] = nullptr;
            }
        };
        TrieNode* root = new TrieNode();
        // insert all words into the trie
        for (auto& word : nums) {
            TrieNode* curr = root;
            for (char ch : word) {
                int key = ch - 'a';
                if (curr->children[key] == nullptr)
                    curr->children[key] = new TrieNode();
                curr = curr->children[key];
            }
            curr->end = true;
        }
        // a word is complete if every prefix (including itself) is marked end
        auto isValid = [&](const string& word) -> bool {
            TrieNode* curr = root;
            for (char ch : word) {
                int key = ch - 'a';
                if (curr->children[key] == nullptr || curr->children[key]->end == false)
                    return false;
                curr = curr->children[key];
            }
            return true;
        };
        string ans = "";
        bool found = false;
        for (auto& word : nums) {
            if (isValid(word)) {
                if (!found) { ans = word; found = true; }
                else if (word.size() > ans.size()) ans = word;
                else if (word.size() == ans.size() && word < ans) ans = word;
            }
        }
        if (!found) return "None";
        return ans;
    }
};

