class Solution {
  public:
    long long solve(vector<int>& bt) {
        sort(bt.begin(), bt.end());
        long long n = (long long)bt.size();
        long long elapsed = 0;    // cumulative time before current process starts
        long long totalWait = 0;  // sum of waiting times
        for (int i = 0; i < (int)bt.size(); ++i) {
            totalWait += elapsed;
            elapsed += bt[i];
        }
        return totalWait / n;     // floor of the average waiting time
    }
};

