class Solution{
  public:
    int rodCutting(vector<int> price, int n) {
        // price[i] = value of a rod piece of length (i+1), 1-based lengths.
        // n = total rod length; here n == price.size().
        // dp[len] = max value obtainable from a rod of length len.
        vector<long long> dp(n + 1, 0);
        for (int len = 1; len <= n; len++) {
            long long best = LLONG_MIN;
            for (int cut = 1; cut <= len; cut++) {
                best = max(best, (long long)price[cut - 1] + dp[len - cut]);
            }
            dp[len] = best;
        }
        return (int)dp[n];
    }
};

class Solution{
public:
    vector<vector<int>> nearest(vector<vector<int>> grid){
        int n = grid.size();
        int m = grid[0].size();
        vector<vector<int>> dist(n, vector<int>(m, 0));
        vector<vector<int>> vis(n, vector<int>(m, 0));
        queue<pair<pair<int,int>,int>> q;
        for(int i = 0; i < n; i++){
            for(int j = 0; j < m; j++){
                if(grid[i][j] == 1){
                    q.push({{i,j},0});
                    vis[i][j] = 1;
                }
            }
        }
        int dr[] = {-1, 0, 1, 0};
        int dc[] = {0, 1, 0, -1};
        while(!q.empty()){
            int r = q.front().first.first;
            int c = q.front().first.second;
            int d = q.front().second;
            q.pop();
            dist[r][c] = d;
            for(int k = 0; k < 4; k++){
                int nr = r + dr[k];
                int nc = c + dc[k];
                if(nr >= 0 && nr < n && nc >= 0 && nc < m && !vis[nr][nc]){
                    vis[nr][nc] = 1;
                    q.push({{nr,nc}, d+1});
                }
            }
        }
        return dist;
    }
};

class Solution {
public:
    bool isArmstrong(int n) {
        long long original = n;
        int digits = 0;
        long long temp = n;
        if (temp == 0) {
            digits = 1;
        } else {
            while (temp > 0) {
                digits++;
                temp /= 10;
            }
        }
        long long sum = 0;
        temp = n;
        if (temp == 0) {
            sum = 0;
        } else {
            while (temp > 0) {
                long long d = temp % 10;
                long long p = 1;
                for (int i = 0; i < digits; i++) p *= d;
                sum += p;
                temp /= 10;
            }
        }
        return sum == original;
    }
};

class Solution{  
  public:  
    vector<int> JobScheduling(vector<vector<int>>& Jobs) { 
        int n = Jobs.size();
        // Sort jobs by profit in descending order (greedy: take most profitable first)
        sort(Jobs.begin(), Jobs.end(), [](const vector<int>& a, const vector<int>& b){
            return a[2] > b[2];
        });
        int maxDeadline = 0;
        for (auto &j : Jobs) maxDeadline = max(maxDeadline, j[1]);
        // slot[t] = -1 means time slot t (1-indexed) is free
        vector<int> slot(maxDeadline + 1, -1);
        long long profit = 0;
        int count = 0;
        for (int i = 0; i < n; i++) {
            int dead = Jobs[i][1];
            // Place job as late as possible (at or before its deadline)
            for (int t = min(dead, maxDeadline); t >= 1; t--) {
                if (slot[t] == -1) {
                    slot[t] = Jobs[i][0];
                    count++;
                    profit += Jobs[i][2];
                    break;
                }
            }
        }
        return {count, (int)profit};
    } 
};

class Solution{
public:
    int numberOfEnclaves(vector<vector<int>> &grid) {
        int n = grid.size();
        if (n == 0) return 0;
        int m = grid[0].size();
        vector<vector<bool>> vis(n, vector<bool>(m, false));
        queue<pair<int,int>> q;
        // push all boundary land cells
        for (int j = 0; j < m; j++) {
            if (grid[0][j] == 1 && !vis[0][j]) { vis[0][j] = true; q.push({0, j}); }
            if (grid[n-1][j] == 1 && !vis[n-1][j]) { vis[n-1][j] = true; q.push({n-1, j}); }
        }
        for (int i = 0; i < n; i++) {
            if (grid[i][0] == 1 && !vis[i][0]) { vis[i][0] = true; q.push({i, 0}); }
            if (grid[i][m-1] == 1 && !vis[i][m-1]) { vis[i][m-1] = true; q.push({i, m-1}); }
        }
        int dr[] = {-1, 0, 1, 0};
        int dc[] = {0, 1, 0, -1};
        while (!q.empty()) {
            auto [r, c] = q.front(); q.pop();
            for (int d = 0; d < 4; d++) {
                int nr = r + dr[d], nc = c + dc[d];
                if (nr >= 0 && nr < n && nc >= 0 && nc < m && !vis[nr][nc] && grid[nr][nc] == 1) {
                    vis[nr][nc] = true;
                    q.push({nr, nc});
                }
            }
        }
        int ans = 0;
        for (int i = 0; i < n; i++)
            for (int j = 0; j < m; j++)
                if (grid[i][j] == 1 && !vis[i][j]) ans++;
        return ans;
    }
};

class Solution {
