    int kthLargestElement(vector<int>& nums, int k) {
        // Min-heap of size k: the top is the k-th largest element.
        priority_queue<int, vector<int>, greater<int>> pq;
        for (int x : nums) {
            pq.push(x);
            if ((int)pq.size() > k) pq.pop();
        }
        return pq.top();
    }
};

class Solution {
public:
int minimumRateToEatBananas(vector<int> nums, int h) {
    int maxPile = 0;
    for (int x : nums) maxPile = max(maxPile, x);
    int lo = 1, hi = maxPile, ans = maxPile;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        long long hours = 0;
        for (int x : nums) {
            hours += (long long)(x + mid - 1) / mid; // ceil(x / mid)
            if (hours > (long long)h) break;
        }
        if (hours <= (long long)h) {
            ans = mid;
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    return ans;
}
};

