    }
};

class Solution {
public:
    int timer = 0;
    void dfs(int node, int parent, vector<int>& vis, vector<vector<int>>& adj,
             vector<int>& tin, vector<int>& low, vector<vector<int>>& bridges) {
        vis[node] = 1;
        tin[node] = low[node] = timer++;
        for (int it : adj[node]) {
            if (it == parent) continue;
            if (!vis[it]) {
                dfs(it, node, vis, adj, tin, low, bridges);
                low[node] = min(low[node], low[it]);
                if (low[it] > tin[node]) {
                    bridges.push_back({min(node, it), max(node, it)});
                }
            } else {
                low[node] = min(low[node], tin[it]);
            }
        }
    }

    vector<vector<int>> criticalConnections(int V, vector<vector<int>>& E) {
        vector<vector<int>> adj(V);
        for (auto& e : E) {
            adj[e[0]].push_back(e[1]);
            adj[e[1]].push_back(e[0]);
        }
        vector<int> vis(V, 0), tin(V, 0), low(V, 0);
        vector<vector<int>> bridges;
        timer = 0;
        for (int i = 0; i < V; i++) {
            if (!vis[i]) dfs(i, -1, vis, adj, tin, low, bridges);
        }
        sort(bridges.begin(), bridges.end());
        return bridges;
    }
};

