class Solution{
  public: int distinctSubsequences(string s, string t){
        const int MOD = 1e9 + 7;
        int n = s.size(), m = t.size();
        // dp[j] = number of distinct subsequences (of the processed prefix of s)
        // that equal the first j characters of t.
        vector<long long> dp(m + 1, 0);
        dp[0] = 1; // empty t can always be formed in exactly 1 way
        for (int i = 1; i <= n; i++) {
            // iterate j from high to low so dp[j-1] refers to the previous row (i-1)
            for (int j = m; j >= 1; j--) {
                if (s[i - 1] == t[j - 1]) {
                    dp[j] = (dp[j] + dp[j - 1]) % MOD;
                }
                // else: dp[j] stays unchanged (exclude s[i-1])
            }
        }
        return (int)(dp[m] % MOD);
    }
};

