class Solution {
public:
    string removeKdigits(string nums, int k) {
        string st;
        for (char c : nums) {
            while (!st.empty() && k > 0 && st.back() > c) {
                st.pop_back();
                k--;
            }
            st.push_back(c);
        }
        // Remove any remaining digits to delete from the back (string is non-decreasing here)
        while (!st.empty() && k > 0) {
            st.pop_back();
            k--;
        }
        // Strip leading zeros
        int i = 0;
        while (i < (int)st.size() && st[i] == '0') i++;
        string ans = st.substr(i);
        return ans.empty() ? "0" : ans;
    }
};

