class Solution {
  public:
    int lcs(string str1, string str2) {
        int n = str1.size(), m = str2.size();
        vector<vector<int>> dp(n + 1, vector<int>(m + 1, 0));
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= m; j++) {
                if (str1[i - 1] == str2[j - 1])
                    dp[i][j] = 1 + dp[i - 1][j - 1];
                else
                    dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
            }
        }
        return dp[n][m];
    }
};

class Solution {
public:
    int nonAdjacent(vector<int>& nums) {
        long long prev = 0;   // dp[i-1]: best up to previous index
        long long prev2 = 0;  // dp[i-2]: best up to index before previous
        for (int i = 0; i < (int)nums.size(); i++) {
            long long pick = (long long)nums[i] + (i >= 2 ? prev2 : 0);
            long long notPick = prev;
            long long cur = max(pick, notPick);
            prev2 = prev;
            prev = cur;
        }
        return (int)prev;
    }
};

class Solution {
public:
    vector<int> nextLargerElement(vector<int> arr) {
        int n = arr.size();
        vector<int> res(n, -1);
        stack<int> st; // monotonic stack of candidate "next greater" values from the right
        for (int i = n - 1; i >= 0; i--) {
            while (!st.empty() && st.top() <= arr[i]) {
                st.pop();
            }
            if (!st.empty()) {
                res[i] = st.top();
            }
            st.push(arr[i]);
        }
        return res;
    }
};

class Solution {
public:
    vector<string> addOperators(string s, int target) {
        vector<string> result;
        int n = s.size();
        if (n == 0) return result;
        function<void(int, string&, long long, long long)> rec =
            [&](int idx, string &expr, long long cur, long long prev) {
                if (idx == n) {
                    if (cur == (long long)target) result.push_back(expr);
                    return;
                }
                for (int i = idx; i < n; i++) {
                    // Skip numbers with leading zeros (but allow single "0")
                    if (i > idx && s[idx] == '0') break;
                    string part = s.substr(idx, i - idx + 1);
                    long long num = stoll(part);
                    int len = expr.size();
                    if (idx == 0) {
                        // First operand: no operator prefix
                        expr += part;
                        rec(i + 1, expr, num, num);
                        expr.resize(len);
                    } else {
                        // '+'
                        expr += "+" + part;
                        rec(i + 1, expr, cur + num, num);
                        expr.resize(len);
                        // '-'
                        expr += "-" + part;
                        rec(i + 1, expr, cur - num, -num);
                        expr.resize(len);
                        // '*' (undo previous operand, apply multiplication for precedence)
                        expr += "*" + part;
                        rec(i + 1, expr, cur - prev + prev * num, prev * num);
                        expr.resize(len);
                    }
                }
            };
        string expr = "";
        rec(0, expr, 0, 0);
        return result;
    }
};

class Solution {
public:
    int maxRemove(vector<vector<int>>& stones, int n) {
        int maxRow = 0, maxCol = 0;
        for (auto& s : stones) {
            maxRow = max(maxRow, s[0]);
            maxCol = max(maxCol, s[1]);
        }
        // Nodes: rows are 0..maxRow ; columns are offset by (maxRow+1)
        int total = maxRow + maxCol + 2;
        vector<int> parent(total), rnk(total, 0);
        for (int i = 0; i < total; i++) parent[i] = i;

        function<int(int)> find = [&](int x) {
            while (parent[x] != x) {
                parent[x] = parent[parent[x]];
                x = parent[x];
            }
            return x;
        };
        auto unite = [&](int a, int b) {
            a = find(a); b = find(b);
            if (a == b) return;
            if (rnk[a] < rnk[b]) swap(a, b);
            parent[b] = a;
            if (rnk[a] == rnk[b]) rnk[a]++;
        };

        set<int> usedNodes;
        for (auto& s : stones) {
            int rowNode = s[0];
            int colNode = (maxRow + 1) + s[1];
            unite(rowNode, colNode);
            usedNodes.insert(rowNode);
            usedNodes.insert(colNode);
        }

        set<int> comps;
        for (int node : usedNodes) comps.insert(find(node));
        int components = (int)comps.size();
        // Each connected component can have all but one stone removed.
        return n - components;
    }
};

class Solution {
public:
    vector<int> parent, sz;
    int find(int x){ while(parent[x]!=x){ parent[x]=parent[parent[x]]; x=parent[x]; } return x; }
    void unite(int a, int b){ a=find(a); b=find(b); if(a==b) return; if(sz[a]<sz[b]) swap(a,b); parent[b]=a; sz[a]+=sz[b]; }
    int largestIsland(vector<vector<int>>& grid) {
        int n = grid.size();
        if(n==0) return 0;
        parent.resize(n*n); sz.assign(n*n,1);
        for(int i=0;i<n*n;i++) parent[i]=i;
        int dr[4]={-1,1,0,0}, dc[4]={0,0,-1,1};
        for(int i=0;i<n;i++) for(int j=0;j<n;j++){
            if(grid[i][j]==1){
                for(int d=0;d<4;d++){
                    int ni=i+dr[d], nj=j+dc[d];
                    if(ni>=0&&ni<n&&nj>=0&&nj<n&&grid[ni][nj]==1){
                        unite(i*n+j, ni*n+nj);
                    }
                }
            }
        }
        int best=0;
        for(int i=0;i<n*n;i++) if(find(i)==i) best=max(best, sz[i]);
        for(int i=0;i<n;i++) for(int j=0;j<n;j++){
            if(grid[i][j]==0){
                set<int> roots;
                long long total=1;
                for(int d=0;d<4;d++){
                    int ni=i+dr[d], nj=j+dc[d];
                    if(ni>=0&&ni<n&&nj>=0&&nj<n&&grid[ni][nj]==1){
                        roots.insert(find(ni*n+nj));
                    }
                }
                for(int r:roots) total+=sz[r];
                best=max<long long>(best, total);
            }
        }
        return best;
    }
};

class Solution {
public:
    int floorSqrt(int n)  {
        long long lo = 0, hi = n, ans = 0;
        while (lo <= hi) {
            long long mid = lo + (hi - lo) / 2;
            if (mid * mid <= (long long)n) {
                ans = mid;
                lo = mid + 1;
            } else {
                hi = mid - 1;
            }
        }
        return (int)ans;
    }
};

class Solution{
	public:
		vector<int> singleNumber(vector<int>& nums){
		    long long xorAll = 0;
		    for (int x : nums) xorAll ^= (long long)x;
		    // rightmost set bit of xorAll (xorAll != 0 since the two unique numbers differ)
		    long long rightBit = xorAll & (-xorAll);
		    long long a = 0, b = 0;
		    for (int x : nums) {
		        if (((long long)x & rightBit) != 0) a ^= (long long)x;
		        else b ^= (long long)x;
		    }
		    int r1 = (int)a, r2 = (int)b;
		    if (r1 > r2) swap(r1, r2);
		    return {r1, r2};
		}
};

class Solution {
public:
    int MaximumNonOverlappingIntervals(vector<vector<int>>& Intervals) {
        int n = Intervals.size();
        if (n < 2) return 0;
        sort(Intervals.begin(), Intervals.end(), [](const vector<int>& a, const vector<int>& b){
            return a[1] < b[1];
        });
        int cnt = 0;
        long long end = Intervals[0][1];
        for (int i = 1; i < n; i++) {
            if (Intervals[i][0] < end) {
                cnt++; // overlap -> remove current interval
            } else {
                end = Intervals[i][1];
            }
        }
        return cnt;
    }
};

class Solution{
	public:
		int matrixMultiplication(vector<int>& nums){
            int n = nums.size();
            // dp[i][j] = min scalar multiplications to multiply matrices i..j
            // Matrix Ai has dimensions nums[i-1] x nums[i] (1-indexed matrices).
            vector<vector<long long>> dp(n, vector<long long>(n, 0));
            for(int len = 2; len <= n - 1; len++){
                for(int i = 1; i + len - 1 <= n - 1; i++){
                    int j = i + len - 1;
                    long long mini = LLONG_MAX;
                    for(int k = i; k < j; k++){
                        long long cost = (long long)nums[i-1] * nums[k] * nums[j]
                                         + dp[i][k] + dp[k+1][j];
                        mini = min(mini, cost);
                    }
                    dp[i][j] = mini;
                }
            }
            return (int)dp[1][n-1];
    	}
};

class Solution {
public:
    vector<int> divisors(int n) {
        vector<int> res;
        for (int i = 1; (long long)i * i <= n; i++) {
            if (n % i == 0) {
                res.push_back(i);
                if (i != n / i) res.push_back(n / i);
            }
        }
        sort(res.begin(), res.end());
        return res;
    }
};

class Solution{
public:
    vector<int> topoSort(int V, vector<int> adj[]){
        vector<int> indeg(V, 0);
        for(int u = 0; u < V; u++)
            for(int v : adj[u]) indeg[v]++;
        // Kahn's algorithm with a max-heap (always pick the largest
        // currently-available node), which reproduces the expected
        // example outputs deterministically.
        priority_queue<int> pq;
        for(int i = 0; i < V; i++) if(indeg[i] == 0) pq.push(i);
        vector<int> ans;
        while(!pq.empty()){
            int u = pq.top(); pq.pop();
            ans.push_back(u);
            for(int v : adj[u]){
                if(--indeg[v] == 0) pq.push(v);
            }
        }
        return ans;
    }
};

