class Solution{
	public:
		int findRangeXOR(int l,int r){
			auto xorUpto = [](long long n) -> long long {
				// XOR of all integers from 0..n (n >= 0)
				switch(n % 4){
					case 0: return n;
					case 1: return 1;
					case 2: return n + 1;
					default: return 0; // case 3
				}
			};
			long long res = xorUpto((long long)r) ^ xorUpto((long long)l - 1);
			return (int)res;
		}
};

class Solution {
public:
    void solve(int idx, vector<int>& nums, vector<int>& cur, vector<vector<int>>& ans) {
        ans.push_back(cur);
        for (int i = idx; i < (int)nums.size(); i++) {
            if (i > idx && nums[i] == nums[i-1]) continue;
            cur.push_back(nums[i]);
            solve(i + 1, nums, cur, ans);
            cur.pop_back();
        }
    }
    vector<vector<int> > subsetsWithDup(vector<int>& nums) {
        sort(nums.begin(), nums.end());
        vector<vector<int>> ans;
        vector<int> cur;
        solve(0, nums, cur, ans);
        return ans;
    }
};

