class Solution{	
	public:	
		bool uniqueBinaryTree(int a, int b){
			// Traversal codes: 1 -> Preorder, 2 -> Inorder, 3 -> Postorder.
			// A unique binary tree can be reconstructed from a pair of traversals
			// if and only if exactly one of the two traversals is Inorder (2).
			// Inorder is required to split nodes into left/right subtrees, and
			// pairing it with Preorder or Postorder yields a unique tree.
			// Preorder+Postorder (or any same-type / non-inorder pair) is ambiguous,
			// and two Inorder traversals are also insufficient.
			return (a == 2) ^ (b == 2);
		}
};

class Solution
{
public:
    int largestRectangleArea(vector<int> &heights){
        int n = heights.size();
        stack<int> st;
        int maxArea = 0;
        for(int i = 0; i <= n; i++){
            int cur = (i == n) ? 0 : heights[i];
            while(!st.empty() && heights[st.top()] >= cur){
                int height = heights[st.top()];
                st.pop();
                int width = st.empty() ? i : (i - st.top() - 1);
                maxArea = max(maxArea, height * width);
            }
            st.push(i);
        }
        return maxArea;
    }
    int maximalAreaOfSubMatrixOfAll1(vector<vector<int>> &matrix){
        if(matrix.empty() || matrix[0].empty()) return 0;
        int m = matrix.size();
        int n = matrix[0].size();
        vector<int> heights(n, 0);
        int maxArea = 0;
        for(int i = 0; i < m; i++){
            for(int j = 0; j < n; j++){
                if(matrix[i][j] == 1) heights[j] += 1;
                else heights[j] = 0;
            }
            maxArea = max(maxArea, largestRectangleArea(heights));
        }
        return maxArea;
    }
};

class Solution {
public:
    vector<vector<int>> fourSum(vector<int>& nums, int target) {
        int n = nums.size();
        sort(nums.begin(), nums.end());
        vector<vector<int>> ans;
        for (int a = 0; a < n; a++) {
            if (a > 0 && nums[a] == nums[a - 1]) continue;
            for (int b = a + 1; b < n; b++) {
                if (b > a + 1 && nums[b] == nums[b - 1]) continue;
                int c = b + 1;
                int d = n - 1;
                while (c < d) {
                    long long sum = (long long)nums[a] + nums[b] + nums[c] + nums[d];
                    if (sum == (long long)target) {
                        ans.push_back({nums[a], nums[b], nums[c], nums[d]});
                        c++;
                        d--;
                        while (c < d && nums[c] == nums[c - 1]) c++;
                        while (c < d && nums[d] == nums[d + 1]) d--;
                    } else if (sum < (long long)target) {
                        c++;
                    } else {
                        d--;
                    }
                }
            }
        }
        return ans;
    }
};

class Solution {
public:
    vector<string> letterCombinations(string digits) {
        vector<string> result;
        if (digits.empty()) return result;
        vector<string> mapping = {
            "", "", "abc", "def", "ghi", "jkl", "mno", "pqrs", "tuv", "wxyz"
        };
        string current;
        function<void(int)> backtrack = [&](int idx) {
            if (idx == (int)digits.size()) {
                result.push_back(current);
                return;
            }
            string letters = mapping[digits[idx] - '0'];
            for (char c : letters) {
                current.push_back(c);
                backtrack(idx + 1);
                current.pop_back();
            }
        };
        backtrack(0);
        return result;
    }
};

class Solution{
    public:
        vector <int> search(string pat, string txt){
            vector<int> result;
            int n = (int)txt.size(), m = (int)pat.size();
            if (m == 0 || m > n) return result;

            // Build LPS (Longest Proper Prefix which is also Suffix) array for the pattern
            vector<int> lps(m, 0);
            for (int i = 1; i < m; i++) {
                int j = lps[i - 1];
                while (j > 0 && pat[i] != pat[j]) {
                    j = lps[j - 1];
                }
                if (pat[i] == pat[j]) {
                    j++;
                }
                lps[i] = j;
            }

            // KMP search over the text; collect all 0-based starting indices (ascending)
            int j = 0; // number of characters of pat currently matched
            for (int i = 0; i < n; i++) {
                while (j > 0 && txt[i] != pat[j]) {
                    j = lps[j - 1];
                }
                if (txt[i] == pat[j]) {
                    j++;
                }
                if (j == m) {
                    result.push_back(i - m + 1);
                    j = lps[j - 1]; // allow overlapping matches
                }
            }
            return result;
        }
};

class Solution{
public:
    int findMedian(vector<vector<int>>&matrix) {
        int n = matrix.size();
        int m = matrix[0].size();
        int low = INT_MAX, high = INT_MIN;
        for (int i = 0; i < n; i++) {
            low = min(low, matrix[i][0]);
            high = max(high, matrix[i][m - 1]);
        }
        // need = number of elements that must lie strictly before the median = (n*m)/2
        long long need = (long long)(n) * m / 2;
        int ans = high;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            long long cnt = 0;
            for (int i = 0; i < n; i++) {
                cnt += upper_bound(matrix[i].begin(), matrix[i].end(), mid) - matrix[i].begin();
            }
            if (cnt <= need) {
                low = mid + 1;
            } else {
                ans = mid;
                high = mid - 1;
            }
        }
        return ans;
    }
};

class Solution {
public:
    int pascalTriangleI(int r, int c) {
        // Value at row r, column c (1-indexed) in Pascal's Triangle = C(r-1, c-1)
        long long n = r - 1;
        long long k = c - 1;
        if (k < 0 || k > n) return 0;
        if (k > n - k) k = n - k; // use symmetry to minimize iterations
        long long res = 1;
        for (long long i = 0; i < k; i++) {
            res = res * (n - i) / (i + 1);
        }
        return (int)res;
    }
};

class Solution{
public:
    bool canFinish(int N, vector<vector<int>> arr) {
        vector<int> indeg(N, 0);
        vector<vector<int>> adj(N);
        // arr[i] = [a, b] => must take b before a => directed edge b -> a
        for (auto &it : arr) {
            int a = it[0], b = it[1];
            adj[b].push_back(a);
            indeg[a]++;
        }
        queue<int> q;
        for (int i = 0; i < N; i++) {
            if (indeg[i] == 0) q.push(i);
        }
        int cnt = 0;
        while (!q.empty()) {
            int node = q.front(); q.pop();
            cnt++;
            for (int v : adj[node]) {
                if (--indeg[v] == 0) q.push(v);
            }
        }
        return cnt == N;
    }
};

class Solution{
public:
    int stockBuySell(vector<int> arr, int n, int k){
        // dp[cap][buy]: max profit, buy=0 means we are free to buy, buy=1 means holding a share.
        // Space-optimized iteration over days from last to first.
        vector<vector<int>> ahead(k+1, vector<int>(2, 0));
        vector<vector<int>> cur(k+1, vector<int>(2, 0));
        for(int ind = n-1; ind >= 0; ind--){
            for(int cap = 1; cap <= k; cap++){
                for(int buy = 0; buy <= 1; buy++){
                    int profit;
                    if(buy == 0){ // free to buy
                        profit = max(-arr[ind] + ahead[cap][1], ahead[cap][0]);
                    } else { // holding, may sell (completes a transaction)
                        profit = max(arr[ind] + ahead[cap-1][0], ahead[cap][1]);
                    }
                    cur[cap][buy] = profit;
                }
            }
            ahead = cur;
        }
        return ahead[k][0];
    }
};

class Solution{   
public: 
  int minInsertion(string s) {
    int n = s.size();
    string r = s;
    reverse(r.begin(), r.end());
    // LCS of s and reverse(s) == longest palindromic subsequence length
    vector<vector<int>> dp(n + 1, vector<int>(n + 1, 0));
    for (int i = 1; i <= n; i++) {
      for (int j = 1; j <= n; j++) {
        if (s[i - 1] == r[j - 1])
          dp[i][j] = dp[i - 1][j - 1] + 1;
        else
          dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
      }
    }
    int lps = dp[n][n];
    return n - lps;
  }
};

class Solution {
public:
    int jump(vector<int>& nums) {
        int n = nums.size();
        int jumps = 0;
        int curEnd = 0;
        int farthest = 0;
        for (int i = 0; i < n - 1; i++) {
            farthest = max(farthest, i + nums[i]);
            if (i == curEnd) {
                jumps++;
                curEnd = farthest;
            }
        }
        return jumps;
    }
};

class Solution {
public:
    int leastInterval(vector<char>& tasks, int n) {
        vector<int> freq(26, 0);
        for (char c : tasks) freq[c - 'A']++;
        int maxFreq = 0;
        for (int f : freq) maxFreq = max(maxFreq, f);
        int countMax = 0;
        for (int f : freq) if (f == maxFreq) countMax++;
        long long part1 = (long long)(maxFreq - 1) * (n + 1) + countMax;
        long long ans = max((long long)tasks.size(), part1);
        return (int)ans;
    }
};

class Solution {
public:
    int findPages(vector<int> &nums, int m)  {
        int n = nums.size();
        if (m > n) return -1;
        long long low = 0, high = 0;
        for (int i = 0; i < n; i++) {
            low = max(low, (long long)nums[i]);
            high += nums[i];
        }
        int ans = -1;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // count minimum students needed if a student may hold at most `mid` pages
            int students = 1;
            long long pagesSum = 0;
            for (int i = 0; i < n; i++) {
                if (pagesSum + nums[i] <= mid) {
                    pagesSum += nums[i];
                } else {
                    students++;
                    pagesSum = nums[i];
                }
            }
            if (students <= m) {
                ans = (int)mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return ans;
    }
};
